// AUTO-GENERATED DRAFT SCREEN: CryptoAccountDeletionScreen

import React, { useState } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Checkbox } from '@/components/ui/checkbox';
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { useMutation } from '@tanstack/react-query'; // Assuming tRPC integrates with react-query
import { Loader2 } from 'lucide-react';

interface CryptoAccountDeletionScreenProps {
  userId: string;
}

const CryptoAccountDeletionScreen: React.FC<CryptoAccountDeletionScreenProps> = ({ userId }) => {
  const [confirmText, setConfirmText] = useState('');
  const [isChecked, setIsChecked] = useState(false);
  const [isDialogOpen, setIsDialogOpen] = useState(false);

  // Mock tRPC mutation hook for account deletion
  // In a real application, this would be generated by tRPC
  const deleteAccountMutation = useMutation({
    mutationFn: async (id: string) => {
      // Simulate API call
      return new Promise((resolve, reject) => {
        setTimeout(() => {
          if (id === 'validUserId') {
            resolve({ success: true });
          } else {
            reject(new Error('Failed to delete account. Please try again.'));
          }
        }, 2000);
      });
    },
    onSuccess: () => {
      alert('Account successfully deleted!');
      setIsDialogOpen(false);
      // Redirect or perform other post-deletion actions
    },
    onError: (error: Error) => {
      alert(`Error: ${error.message}`);
    },
  });

  const handleDeleteAccount = () => {
    if (confirmText === 'DELETE' && isChecked) {
      deleteAccountMutation.mutate(userId);
    } else {
      alert('Please type DELETE and confirm the checkbox to proceed.');
    }
  };

  const isDeleteButtonDisabled = confirmText !== 'DELETE' || !isChecked || deleteAccountMutation.isPending;

  return (
    <div className="flex flex-col items-center justify-center min-h-screen bg-background text-foreground p-4 dark:bg-gray-900 dark:text-gray-100">
      <div className="w-full max-w-md p-8 space-y-6 bg-card rounded-lg shadow-lg dark:bg-gray-800">
        <h1 className="text-3xl font-bold text-center">Account Deletion</h1>
        <p className="text-center text-muted-foreground dark:text-gray-300">
          This action is irreversible. All your data will be permanently deleted.
          Please type &quot;DELETE&quot; below to confirm.
        </p>

        <div className="space-y-4">
          <Input
            type="text"
            placeholder="Type DELETE to confirm"
            value={confirmText}
            onChange={(e) => setConfirmText(e.target.value)}
            className="w-full bg-input dark:bg-gray-700 dark:text-gray-100 border-border dark:border-gray-600"
            aria-label="Confirm deletion by typing DELETE"
          />
          <div className="flex items-center space-x-2">
            <Checkbox
              id="confirm-checkbox"
              checked={isChecked}
              onCheckedChange={(checked) => setIsChecked(checked as boolean)}
              className="data-[state=checked]:bg-primary data-[state=checked]:text-primary-foreground dark:data-[state=checked]:bg-blue-500 dark:data-[state=checked]:text-white"
            />
            <label
              htmlFor="confirm-checkbox"
              className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70"
            >
              I understand the consequences.
            </label>
          </div>
        </div>

        {deleteAccountMutation.isError && (
          <p className="text-red-500 text-center text-sm" role="alert">
            {deleteAccountMutation.error?.message || 'An unknown error occurred.'}
          </p>
        )}

        <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
          <DialogTrigger asChild>
            <Button
              variant="destructive"
              onClick={() => setIsDialogOpen(true)}
              disabled={isDeleteButtonDisabled}
              className="w-full"
            >
              {deleteAccountMutation.isPending ? (
                <Loader2 className="mr-2 h-4 w-4 animate-spin" aria-label="Deleting account..." />
              ) : (
                'Delete My Account'
              )}
            </Button>
          </DialogTrigger>
          <DialogContent className="sm:max-w-[425px] bg-card dark:bg-gray-800 text-foreground dark:text-gray-100">
            <DialogHeader>
              <DialogTitle>Are you absolutely sure?</DialogTitle>
              <DialogDescription>
                This action cannot be undone. This will permanently delete your account
                and remove your data from our servers.
              </DialogDescription>
            </DialogHeader>
            <DialogFooter>
              <Button variant="outline" onClick={() => setIsDialogOpen(false)} className="dark:border-gray-600 dark:text-gray-100">Cancel</Button>
              <Button
                variant="destructive"
                onClick={handleDeleteAccount}
                disabled={deleteAccountMutation.isPending}
              >
                {deleteAccountMutation.isPending ? (
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" aria-label="Confirming deletion..." />
                ) : (
                  'Confirm Deletion'
                )}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>
    </div>
  );
};

export default CryptoAccountDeletionScreen;
